mapper.insert:
/* OrgnAgenCnptDataMapper.callOrgnAgenData */
{ CALL P_MDS_ORGN_AGEN_INFO(
				#{i_DATE, mode=IN, jdbcType=VARCHAR}
				, #{O_CODE, mode=OUT, jdbcType=VARCHAR}
				, #{O_MSG, mode=OUT, jdbcType=VARCHAR}
			) }

/* OrgnAgenCnptDataMapper.callOrgnCnptData */
{ CALL P_MDS_ORGN_CNPT_INFO(
				#{i_DATE , mode=IN, jdbcType=VARCHAR}
				, #{O_CODE, mode=OUT, jdbcType=VARCHAR}
				, #{O_MSG, mode=OUT, jdbcType=VARCHAR}
			)}

mapper.delete:
/* OrgnAgenCnptDataMapper.deleteOrgAgenData */
DELETE FROM MDS_AGNT_INFO_TMP
WHERE FILE_NM  <>  'KIS_OG_AGNCY_BAS_' || TO_CHAR(SYSDATE-1 , YYYYMMDD) || '.DAT'

/* OrgnAgenCnptDataMapper.deleteOrgCpntData */
DELETE FROM MDS_ORG_CPNT_INFO_TMP
WHERE FILE_NM  <>  'KIS_OG_CPNT_BAS_' || TO_CHAR(SYSDATE-1 , YYYYMMDD) || '.DAT'

/* OrgnAgenCnptDataMapper.deleteOrgRelData */
DELETE FROM MDS_ORG_REL_INFO_TMP
WHERE FILE_NM  <>  'KIS_OG_ORG_REL_BAS_' || TO_CHAR(SYSDATE-1 , YYYYMMDD) || '.DAT'
